import{initTodoApp as t}from"../features/todo.js";export function renderTodo(o){return o.innerHTML='<div class="container"><header class="section__header"><p class="section__subtitle">Task Manager</p><h1>To-Do List</h1></header><section id="todo-app" class="todo-app"><div id="todo-live-region" class="sr-only" aria-live="polite"></div><form id="todo-form" class="todo-form" aria-label="Add a new task"><label for="todo-input" class="form__label">New task</label><div class="todo-form__row"><input type="text" id="todo-input" class="form__input todo-form__input" required maxlength="200"><button type="submit" class="btn btn--primary">Add Task</button></div></form><div id="todo-filters" class="todo-filters" role="group" aria-label="Filter tasks"><button type="button" class="todo-filter todo-filter--active" data-filter="all" aria-pressed="true">All</button><button type="button" class="todo-filter" data-filter="active" aria-pressed="false">Active</button><button type="button" class="todo-filter" data-filter="completed" aria-pressed="false">Completed</button></div><p id="todo-stats" class="todo-stats">0 active, 0 completed, 0 total</p><p id="todo-empty" class="todo-empty" hidden>No tasks to show.</p><ul id="todo-list" class="todo-list" role="list"></ul><button type="button" id="todo-clear-completed" class="btn btn--secondary todo-clear" hidden>Clear completed</button></section></div>',t()}